// Sadə optional chaining
const user = {
  name: 'Ali',
  address: {
    city: 'Baku'
  }
};

console.log(user.address?.city); // Baku
console.log(user.profile?.age); // undefined

// Metodlarda optional chaining
const person = {
  name: 'Veli',
  greet: function() {
    return 'Salam, ' + this.name;
  }
};

console.log(person.greet?.()); // Salam, Veli
console.log(person.sayGoodbye?.()); // undefined

// Səhvə yol açan nümunə
const data = {
  user: {
    profile: {
      name: 'Aysu'
    }
  }
};

// Ənənəvi üsul (səhvə səbəb ola bilər)
console.log(data.user.profile.name); // Aysu
console.log(data.user.settings.theme); // TypeError

// Optional chaining ilə düzgün yol
console.log(data.user?.profile?.name); // Aysu
console.log(data.user?.settings?.theme); // undefined

// Şərtli yoxlama ilə
const user = {
  profile: {
    name: 'Veli'
  }
};

// Ənənəvi üsul
let name;
if (user && user.profile && user.profile.name) {
  name = user.profile.name;
} else {
  name = 'Unknown';
}
console.log(name); // Veli

// Optional chaining ilə
const name2 = user.profile?.name ?? 'Unknown';
console.log(name2); // Veli

