// Simple optional chaining
const user = {
  name: 'Ali',
  address: {
    city: 'Baku'
  }
};

console.log(user.address?.city); // Baku
console.log(user.profile?.age); // undefined

// Optional chaining with methods
const person = {
  name: 'Veli',
  greet: function() {
    return 'Hello, ' + this.name;
  }
};

console.log(person.greet?.()); // Hello, Veli
console.log(person.sayGoodbye?.()); // undefined

// Error-prone example
const data = {
  user: {
    profile: {
      name: 'Aysu'
    }
  }
};

// Traditional approach (may cause error)
console.log(data.user.profile.name); // Aysu
console.log(data.user.settings.theme); // TypeError

// Correct approach with optional chaining
console.log(data.user?.profile?.name); // Aysu
console.log(data.user?.settings?.theme); // undefined

// With conditional checks
const user = {
  profile: {
    name: 'Veli'
  }
};

// Traditional approach
let name;
if (user && user.profile && user.profile.name) {
  name = user.profile.name;
} else {
  name = 'Unknown';
}
console.log(name); // Veli

// With optional chaining
const name2 = user.profile?.name ?? 'Unknown';
console.log(name2); // Veli

