// Простая опциональная цепочка
const user = {
  name: 'Али',
  address: {
    city: 'Баку'
  }
};

console.log(user.address?.city); // Баку
console.log(user.profile?.age); // undefined

// Опциональная цепочка с методами
const person = {
  name: 'Вали',
  greet: function() {
    return 'Привет, ' + this.name;
  }
};

console.log(person.greet?.()); // Привет, Вали
console.log(person.sayGoodbye?.()); // undefined

// Пример с ошибкой
const data = {
  user: {
    profile: {
      name: 'Айсу'
    }
  }
};

// Традиционный подход (может вызвать ошибку)
console.log(data.user.profile.name); // Айсу
console.log(data.user.settings.theme); // TypeError

// Правильный подход с опциональной цепочкой
console.log(data.user?.profile?.name); // Айсу
console.log(data.user?.settings?.theme); // undefined

// С условными проверками
const user = {
  profile: {
    name: 'Вали'
  }
};

// Традиционный подход
let name;
if (user && user.profile && user.profile.name) {
  name = user.profile.name;
} else {
  name = 'Unknown';
}
console.log(name); // Вали

// С опциональной цепочкой
const name2 = user.profile?.name ?? 'Unknown';
console.log(name2); // Вали

